import React from 'react';
import ReactDOM from 'react-dom';
import {
  MainContainer,
  ChatContainer,
  MessageList,
  Message,
  MessageInput
} from '@chatscope/chat-ui-kit-react';
import '@chatscope/chat-ui-kit-styles/dist/default/styles.min.css';

const Chatting = () => {
  return (
        <MainContainer>
          <ul>
            <li></li>
            <li style={{ width: 790, height: 888}}><ChatContainer>
            <MessageList>
              <Message
                model={{
                  message: '안녕',
                  direction: 'incoming',
                  position: 'first',
                }}
              />
              <Message
                model={{
                  message: '나도 안녕',
                  direction: 'outgoing',
                  position: 'first',
                }}
              />
            </MessageList>
            <MessageInput placeholder="메세지 작성" />
          </ChatContainer>
          </li>

          </ul>
        </MainContainer>
  );
};


export default Chatting;
